+#[test]
+fn humanize_rejects_tracked_unterminated_suffix() {
+    unsafe {
+        let suffix = malloc_unterminated(b"/s");
+        let mut buf = [0u8; 32];
+
+        let n = humanize_number(
+            buf.as_mut_ptr() as *mut c_char,
+            buf.len(),
+            4096,
+            suffix,
+            HN_AUTOSCALE,
+            HN_IEC_PREFIXES | HN_B,
+        );
+
+        frankenlibc_abi::malloc_abi::free(suffix.cast());
+        assert_eq!(n, -1);
+    }
+}
